`,readingTime:{minutes:.04,words:12},title:"References",type:"article"}}],["/GameEngine/Unity/manual/normal/Multi-Platform.html",{loader:()=>c(()=>import("./Multi-Platform.html-C3cDwefP.js"),__vite__mapDeps([463,1])),meta:{date:1606775195e3,localizedDate:"November 30, 2020",tag:["Unity"],excerpt:`
